    // ─── Xuất hóa đơn → PDF ─────────────────────────────────────────
    // ─── Bỏ dấu tiếng Việt → ASCII (dùng cho jsPDF vì Helvetica không hỗ trợ Unicode)
    function normalizePdfText(str) {
      if (!str) return '';
      // Các ký tự cơ bản tiếng Việt không decompose qua NFD
      const map = {
        'ơ':'o','Ơ':'O','ư':'u','Ư':'U','đ':'d','Đ':'D',
        'ă':'a','Ă':'A','â':'a','Â':'A','ê':'e','Ê':'E',
        'ô':'o','Ô':'O'
      };
      str = str.replace(/[ơƠưƯđĐăĂâÂêÊôÔ]/g, c => map[c] ?? c);
      // Bỏ các combining diacritical marks còn lại (hỏi/ngã/sắc/huyền/nặng)
      return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    }

    function fmtVndPdf(n) {
      // Dùng dấu chấm thập phân để tương thích font Latin (tránh lỗi ký tự '.')
      return Number(n || 0).toLocaleString('en-US') + ' VND';
    }

    function exportAdminInvoicesPDF() {
      if (typeof window.jspdf === 'undefined') { alert('Thư viện xuất PDF chưa tải xong, vui lòng thử lại.'); return; }
      const { jsPDF } = window.jspdf;
      const rows = adminDashboardData?.payments || [];
      if (!rows.length) { alert('Không có hóa đơn để xuất.'); return; }
      const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const pageW = doc.internal.pageSize.getWidth();
      const today = new Date();
      const dateStr = `${today.getDate()}/${today.getMonth() + 1}/${today.getFullYear()}`;

      // Tiêu đề (toàn ASCII — an toàn với Helvetica)
      doc.setFillColor(30, 58, 95);
      doc.rect(0, 0, pageW, 22, 'F');
      doc.setTextColor(255, 255, 255);
      doc.setFontSize(15);
      doc.setFont('helvetica', 'bold');
      doc.text('DANH SACH HOA DON THANH TOAN', pageW / 2, 10, { align: 'center' });
      doc.setFontSize(9);
      doc.setFont('helvetica', 'normal');
      doc.text(`Xuat ngay: ${dateStr}  |  Tong so: ${rows.length} giao dich`, pageW / 2, 17, { align: 'center' });

      // Cột và header
      const colW = [24, 32, 34, 42, 22, 20, 28, 14, 26, 16];
      const headers = ['Ngay', 'Ma HD', 'Khach hang', 'Email', 'Loai', 'Goi', 'So tien', 'Luot', 'So du nap', 'TT'];
      let y = 28;

      const drawRow = (cells, rowY, isBold, bgRgb) => {
        let x = 6;
        if (bgRgb) {
          doc.setFillColor(...bgRgb);
          doc.rect(x - 1, rowY - 4.5, pageW - 10, 7.5, 'F');
        }
        doc.setFont('helvetica', isBold ? 'bold' : 'normal');
        doc.setTextColor(isBold ? 255 : 25, isBold ? 255 : 35, isBold ? 255 : 55);
        doc.setFontSize(7.5);
        cells.forEach((cell, i) => {
          // Giới hạn độ dài + bỏ dấu để font hiển thị đúng
          const raw = normalizePdfText(String(cell ?? ''));
          const maxChars = Math.floor(colW[i] / 1.85);
          const txt = raw.length > maxChars ? raw.substring(0, maxChars - 1) + '.' : raw;
          doc.text(txt, x + 1, rowY);
          x += colW[i];
        });
      };

      drawRow(headers, y, true, [30, 58, 95]);
      y += 8.5;

      rows.forEach((r, idx) => {
        if (y > 188) {
          doc.addPage();
          y = 14;
          drawRow(headers, y, true, [30, 58, 95]);
          y += 8.5;
        }
        const bg = idx % 2 === 0 ? [238, 244, 255] : [250, 252, 255];
        const cells = [
          formatPortalDate(r.paid_at || r.created_at, ''),
          (r.payment_code || r.id || '').substring(0, 16),
          r.name || '',
          r.email || '',
          r.order_type === 'wallet_topup' ? 'Nap so du' : 'Mua luot VIP',
          r.plan_id || '',
          fmtVndPdf(r.amount_vnd),
          String(r.credits_granted || 0),
          fmtVndPdf(r.wallet_amount_vnd),
          r.status || ''
        ];
        drawRow(cells, y, false, bg);
        y += 7.5;
      });

      // Đường kẻ cuối + tổng kết
      doc.setDrawColor(180, 190, 210);
      doc.line(6, y + 1, pageW - 6, y + 1);
      doc.setTextColor(80, 95, 120);
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(8);
      const totalRevenue = rows.filter(r => r.status === 'paid').reduce((s, r) => s + Number(r.amount_vnd || 0), 0);
      doc.text(`Tong doanh thu (paid): ${fmtVndPdf(totalRevenue)}`, 6, y + 7);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(140, 150, 165);
      doc.setFontSize(7);
      doc.text('Bao cao duoc xuat tu He thong Tra cuu Tap chi', pageW - 6, y + 7, { align: 'right' });

      doc.save(`hoa-don-${new Date().toISOString().slice(0, 10)}.pdf`);
    }

    // ─── Xuất báo cáo tổng hợp → Excel ──────────────────────────────
    function exportAdminSummary() {
      if (typeof XLSX === 'undefined') { alert('Thư viện xuất Excel chưa tải xong, vui lòng thử lại.'); return; }
      const payments = adminDashboardData?.payments || [];
      const metrics = adminDashboardData?.metrics || {};
      const users = adminDashboardData?.users || [];
      const wb = XLSX.utils.book_new();

      // Sheet 1: Tổng quan
      const overviewHeaders = ['Chỉ số', 'Giá trị'];
      const overviewData = [
        ['Tổng doanh thu (VND)', Number(metrics.revenue_vnd || 0)],
        ['Số người dùng VIP', Number(metrics.vip_users || 0)],
        ['Tổng tài khoản', Number(metrics.total_users || 0)],
        ['Tổng lượt dùng AI', Number(metrics.ai_uses || 0)],
        ['Ngày xuất báo cáo', new Date().toLocaleDateString('vi-VN')]
      ];
      const ws1 = XLSX.utils.aoa_to_sheet([overviewHeaders, ...overviewData]);
      ws1['!cols'] = [{ wch: 28 }, { wch: 20 }];
      _xlsxStyleHeader(ws1, overviewHeaders);
      XLSX.utils.book_append_sheet(wb, ws1, 'Tổng quan');

      // Sheet 2: Doanh thu theo tháng
      const byMonth = {};
      payments.forEach(p => {
        if (p.status !== 'paid') return;
        const d = new Date(p.paid_at || p.created_at);
        const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
        if (!byMonth[key]) byMonth[key] = { month: key, count: 0, revenue: 0, credits: 0, wallet: 0 };
        byMonth[key].count++;
        byMonth[key].revenue += Number(p.amount_vnd || 0);
        byMonth[key].credits += Number(p.credits_granted || 0);
        byMonth[key].wallet += Number(p.wallet_amount_vnd || 0);
      });
      const monthHeaders = ['Tháng', 'Số giao dịch', 'Doanh thu (VND)', 'Lượt VIP cộng', 'Số dư nạp (VND)'];
      const monthRows = Object.values(byMonth).sort((a, b) => a.month.localeCompare(b.month))
        .map(m => [m.month, m.count, m.revenue, m.credits, m.wallet]);
      const ws2 = XLSX.utils.aoa_to_sheet([monthHeaders, ...monthRows]);
      ws2['!cols'] = [{ wch: 12 }, { wch: 16 }, { wch: 18 }, { wch: 16 }, { wch: 18 }];
      _xlsxStyleHeader(ws2, monthHeaders);
      XLSX.utils.book_append_sheet(wb, ws2, 'Doanh thu theo tháng');

      // Sheet 3: Hóa đơn đầy đủ
      const invHeaders = ['Ngày', 'Mã hóa đơn', 'Khách hàng', 'Email', 'Loại', 'Gói', 'Số tiền (VND)', 'Lượt cộng', 'Số dư nạp (VND)', 'Trạng thái'];
      const invRows = payments.map(r => ([
        formatPortalDate(r.paid_at || r.created_at, ''),
        r.payment_code || r.id || '',
        r.name || '',
        r.email || '',
        r.order_type === 'wallet_topup' ? 'Nạp số dư' : 'Mua lượt VIP',
        r.plan_id || '',
        Number(r.amount_vnd || 0),
        Number(r.credits_granted || 0),
        Number(r.wallet_amount_vnd || 0),
        r.status || ''
      ]));
      const ws3 = XLSX.utils.aoa_to_sheet([invHeaders, ...invRows]);
      ws3['!cols'] = [{ wch: 18 }, { wch: 20 }, { wch: 22 }, { wch: 30 }, { wch: 14 }, { wch: 16 }, { wch: 16 }, { wch: 12 }, { wch: 16 }, { wch: 12 }];
      _xlsxStyleHeader(ws3, invHeaders);
      XLSX.utils.book_append_sheet(wb, ws3, 'Hóa đơn');

      // Sheet 4: Người dùng
      const userHeaders = ['Tên', 'Email', 'Vai trò', 'VIP', 'Lượt còn lại', 'Số dư (VND)', 'Trial đến'];
      const userRows = users.map(u => ([
        u.name || '',
        u.email || '',
        u.role || 'user',
        u.is_vip ? 'Có' : 'Không',
        Number(u.subscription?.ai_credits_remaining || 0),
        Number(u.subscription?.wallet_balance_vnd || 0),
        formatPortalDate(u.subscription?.trial_ends_at, '')
      ]));
      const ws4 = XLSX.utils.aoa_to_sheet([userHeaders, ...userRows]);
      ws4['!cols'] = [{ wch: 24 }, { wch: 32 }, { wch: 10 }, { wch: 6 }, { wch: 12 }, { wch: 14 }, { wch: 18 }];
      _xlsxStyleHeader(ws4, userHeaders);
      XLSX.utils.book_append_sheet(wb, ws4, 'Người dùng');

      _downloadXlsx(wb, `bao-cao-tong-hop-${new Date().toISOString().slice(0, 10)}.xlsx`);
    }

    async function changePortalPassword(event) {
      event.preventDefault();
      const form = event.currentTarget;
      const passwordFields = [...form.querySelectorAll('input[type="password"]')];
      const nextPassword = passwordFields[passwordFields.length - 2]?.value || '';
      const confirmPassword = passwordFields[passwordFields.length - 1]?.value || '';
      const message = form.querySelector('.vip-message') || document.getElementById('portalPasswordMessage');
      if (nextPassword !== confirmPassword) {
        if (message) {
          message.textContent = 'Mật khẩu xác nhận chưa khớp.';
          message.className = 'vip-message error';
        }
        return;
      }
      const { error } = await auth.updatePassword(nextPassword);
      if (message) {
        message.textContent = error ? error.message : 'Đã cập nhật mật khẩu.';
        message.className = `vip-message ${error ? 'error' : 'success'}`;
      }
      if (!error) form.reset();
    }

    async function refreshAccount() {
      if (!currentSession) return null;
      if (accountRefreshPromise) return accountRefreshPromise;

      accountRefreshPromise = (async () => {
        try {
          currentAccount = await apiFetch('/api/account');
          renderAccount(currentAccount);
          syncRealtimeSubscriptions(currentAccount);
          const portal = document.getElementById('accountPortal');
          if (portal?.classList.contains('open')) {
            renderPortalTables();
            renderPortalCharts();
            if (isAdminAccount(currentAccount)) {
              const activePage = document.querySelector('.portal-page.active')?.id;
              if (!activePage || activePage === 'userOverview') switchPortalPage('adminDashboard');
              void loadAdminDashboard();
            }
          }
          return currentAccount;
        } catch (error) {
          if (error.status !== 401) setUserMessage(error.message, 'error');
          return null;
        } finally {
          accountRefreshPromise = null;
        }
      })();

      return accountRefreshPromise;
    }

    function updateAuthUi() {
      const button = document.getElementById('accountButton');
      if (currentSession?.user) {
        if (button) button.innerHTML = '<i class="fas fa-user-check"></i> Tài khoản';
      } else {
        if (button) button.innerHTML = '<i class="fas fa-user"></i> Đăng nhập';
        const chatAccessNote = document.getElementById('chat-access-note');
        if (chatAccessNote) chatAccessNote.style.display = 'block';
      }
      const recovering = passwordRecoveryActive || passwordRecoveryRequested;
      const authView = document.getElementById('authView');
      const accountView = document.getElementById('accountView');
      if (authView) authView.style.display = recovering || !currentSession ? 'block' : 'none';
      if (accountView) accountView.style.display = currentSession && !recovering ? 'block' : 'none';
    }

    async function initAuth() {
      currentSession = await auth.getSession();
      updateAuthUi();
      passwordRecoveryRequested = passwordRecoveryRequested
        || new URL(location.href).searchParams.get('recovery') === '1'
        || new URL(location.href).searchParams.get('type') === 'recovery'
        || new URLSearchParams(location.hash.slice(1)).get('type') === 'recovery';
      if (currentSession && passwordRecoveryRequested) {
        showPasswordRecovery();
      } else if (currentSession) {
        await refreshAccount();
        await handlePortalRouting();
      } else if (passwordRecoveryRequested) {
        if (hasLocalAuthForm()) {
          openUserModal(true);
          setAuthMode('login');
          setUserMessage('Liên kết đặt lại mật khẩu không hợp lệ hoặc đã hết hạn. Hãy yêu cầu liên kết mới.', 'error');
        } else {
          redirectToSharedAuth('reset');
        }
      } else if (isPortalRoute()) {
        redirectToSharedAuth('login');
      }
      auth.onAuthStateChange((event, session) => {
        currentSession = session;
        if (event === 'SIGNED_OUT' || event === 'USER_DELETED') {
          currentAccount = null;
          resetRealtimeSubscriptions();
        }
        setTimeout(async () => {
          updateAuthUi();
          if (event === 'PASSWORD_RECOVERY') {
            showPasswordRecovery();
          } else if (event === 'SIGNED_IN' && session && !passwordRecoveryActive && !passwordRecoveryRequested) {
            currentAccount = null;
            await refreshAccount();
            const authView = document.getElementById('authView');
            const accountView = document.getElementById('accountView');
            if (authView) authView.style.display = 'none';
            if (accountView) accountView.style.display = 'block';
            await handlePortalRouting();
          }
        }, 0);
      });
    }

    function stopPaymentPolling() {
      if (paymentPollTimer) clearTimeout(paymentPollTimer);
      paymentPollTimer = null;
    }

    async function finishPaidPayment() {
      activePaymentCode = null;
      stopPaymentPolling();
      document.getElementById('paymentBox').classList.remove('open');
      document.getElementById('paymentQr').removeAttribute('src');
      setUserMessage('Thanh toán thành công! VIP đã được kích hoạt.', 'success');
      await refreshAccount();
      renderPortalTables();
      renderPortalCharts();
      if (isAdminAccount()) void loadAdminDashboard();
      closeUserModal();
    }

    async function pollPayment(code, expiresAt) {
      stopPaymentPolling();
      const countdown = document.getElementById('paymentCountdown');
      const tick = async () => {
        const remaining = new Date(expiresAt).getTime() - Date.now();
        if (remaining <= 0) {
          countdown.textContent = 'Đơn thanh toán đã hết hạn.';
          countdown.className = 'vip-message error';
          return;
        }
        const minutes = String(Math.floor(remaining / 60000)).padStart(2, '0');
        const seconds = String(Math.floor((remaining % 60000) / 1000)).padStart(2, '0');
        countdown.textContent = `Đang chờ thanh toán · ${minutes}:${seconds}`;
        try {
          const order = await apiFetch(`/api/orders/${encodeURIComponent(code)}/status`);
          if (order.status === 'paid') {
            await finishPaidPayment();
            return;
          }
        } catch (_) { }
        paymentPollTimer = setTimeout(tick, 4000);
      };
      tick();
    }

    async function createPaymentOrder(orderType = 'vip_credits', amountVnd = 0) {
      setUserMessage(orderType === 'wallet_topup' ? 'Đang tạo mã nạp số dư...' : 'Đang tạo mã thanh toán...');
      try {
        const order = await apiFetch('/api/orders', {
          method: 'POST',
          body: JSON.stringify({
            order_type: orderType,
            ...(orderType === 'wallet_topup' ? { amount_vnd: amountVnd } : {})
          })
        });
        activePaymentCode = order.code;
        currentAccount = currentAccount || { user: currentSession?.user, payments: [] };
        currentAccount.payments = currentAccount.payments || [];
        if (!currentAccount.payments.some(payment => payment.payment_code === order.code)) {
          currentAccount.payments.unshift({
            id: order.id,
            payment_code: order.code,
            amount_vnd: order.amount,
            status: order.status || 'pending',
            order_type: order.order_type || orderType,
            created_at: new Date().toISOString(),
            expires_at: order.expires_at
          });
        }
        renderPortalTables();
        document.getElementById('paymentQr').src = order.qr_url;
        document.getElementById('paymentCode').textContent = order.code;
        document.getElementById('paymentAmount').textContent = new Intl.NumberFormat('vi-VN', {
          style: 'currency', currency: 'VND'
        }).format(order.amount);
        document.getElementById('paymentBox').classList.add('open');
        setUserMessage('Quét QR và giữ nguyên nội dung chuyển khoản.', 'success');
        pollPayment(order.code, order.expires_at);
      } catch (error) {
        setUserMessage(error.message, 'error');
      }
    }

    async function createVipOrder() {
      await createPaymentOrder('vip_credits');
    }

    function createWalletTopupOrder() {
      openWalletTopupModal();
    }

    function openWalletTopupModal() {
      const modal = document.getElementById('walletTopupModal');
      const input = document.getElementById('walletTopupAmount');
      const message = document.getElementById('walletTopupMessage');
      if (message) {
        message.textContent = '';
        message.className = 'vip-message';
      }
      modal.classList.add('open');
      setTimeout(() => input?.focus(), 50);
    }

    function closeWalletTopupModal() {
      document.getElementById('walletTopupModal')?.classList.remove('open');
    }

    function setWalletTopupAmount(amount) {
      const input = document.getElementById('walletTopupAmount');
      if (input) input.value = amount;
    }

    async function submitWalletTopup(event) {
      event.preventDefault();
      const input = document.getElementById('walletTopupAmount');
      const message = document.getElementById('walletTopupMessage');
      const amount = Number(input?.value || 0);
      if (!Number.isSafeInteger(amount) || amount < 1000) {
        if (message) {
          message.textContent = 'Số tiền nạp tối thiểu là 1.000đ.';
          message.className = 'vip-message error';
        }
        return;
      }
      closeWalletTopupModal();
      await createPaymentOrder('wallet_topup', amount);
    }
