export function initAccountEvents() {
  const on = (selector, event, handler) => document.querySelector(selector)?.addEventListener(event, handler)

  on('#accountButton', 'click', () => openUserModal())
  on('#userModal', 'click', event => { if (event.target === event.currentTarget) closeUserModal() })
  on('#loginTab', 'click', () => setAuthMode('login'))
  on('#registerTab', 'click', () => setAuthMode('register'))
  on('#passwordResetRequest', 'click', requestPasswordReset)
  on('#authForm', 'submit', submitAuth)
  on('#resetView', 'submit', saveNewPassword)
  on('#walletTopupForm', 'submit', submitWalletTopup)
  document.querySelectorAll('[data-action="change-portal-password"]').forEach(form => form.addEventListener('submit', changePortalPassword))
  on('#authPasswordToggle', 'click', event => togglePasswordVisibility('authPassword', event.currentTarget))
  on('#newPassword', 'input', event => updatePasswordRules(event.currentTarget.value))
  on('#newPasswordToggle', 'click', event => togglePasswordVisibility('newPassword', event.currentTarget))
  on('#confirmNewPasswordToggle', 'click', event => togglePasswordVisibility('confirmNewPassword', event.currentTarget))

  document.querySelectorAll('[data-action="close-user-modal"]').forEach(button => button.addEventListener('click', closeUserModal))
  document.querySelectorAll('[data-action="create-vip-order"]').forEach(button => button.addEventListener('click', createVipOrder))
  document.querySelectorAll('[data-action="create-vip-order-and-open"]').forEach(button => button.addEventListener('click', async () => { await createVipOrder(); openUserModal(true) }))
  document.querySelectorAll('[data-action="create-wallet-topup-order"]').forEach(button => button.addEventListener('click', createWalletTopupOrder))
  document.querySelectorAll('[data-action="create-wallet-topup-order-and-open"]').forEach(button => button.addEventListener('click', () => { createWalletTopupOrder(); openUserModal(true) }))
  document.querySelectorAll('[data-action="sign-out"]').forEach(button => button.addEventListener('click', signOutUser))

  on('#walletTopupModal', 'click', event => { if (event.target === event.currentTarget) closeWalletTopupModal() })
  document.querySelectorAll('[data-action="close-wallet-topup-modal"]').forEach(button => button.addEventListener('click', closeWalletTopupModal))
  document.querySelectorAll('[data-action="close-account-portal"]').forEach(button => button.addEventListener('click', closeAccountPortal))
  document.querySelectorAll('[data-wallet-amount]').forEach(button => {
    button.addEventListener('click', () => setWalletTopupAmount(Number(button.dataset.walletAmount || 0)))
  })

  on('.portal-nav-backdrop', 'click', () => togglePortalNav(false))
  on('.portal-menu-toggle', 'click', () => togglePortalNav())
  document.querySelectorAll('[data-portal-page]').forEach(button => {
    button.addEventListener('click', () => switchPortalPage(button.dataset.portalPage))
  })
  document.querySelectorAll('[data-user-chart-mode]').forEach(button => {
    button.addEventListener('click', () => setUserChartMode(button.dataset.userChartMode))
  })
  document.querySelectorAll('[data-admin-chart-mode]').forEach(button => {
    button.addEventListener('click', () => setAdminChartMode(button.dataset.adminChartMode))
  })
  on('[data-action="portal-smart-transactions"]', 'click', () => switchPortalPage(isAdminAccount() ? 'adminInvoices' : 'userTransactions'))
  on('[data-action="export-admin-summary"]', 'click', exportAdminSummary)
  on('[data-action="export-admin-users"]', 'click', exportAdminUsers)
  on('[data-action="export-admin-invoices"]', 'click', exportAdminInvoices)
  on('[data-action="export-admin-invoices-pdf"]', 'click', exportAdminInvoicesPDF)
  on('[data-action="save-admin-settings"]', 'click', saveAdminSettings)
}
